package com.example.muye.contract;

import java.math.BigInteger;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;
import org.fisco.bcos.sdk.abi.FunctionReturnDecoder;
import org.fisco.bcos.sdk.abi.TypeReference;
import org.fisco.bcos.sdk.abi.datatypes.Event;
import org.fisco.bcos.sdk.abi.datatypes.Function;
import org.fisco.bcos.sdk.abi.datatypes.Type;
import org.fisco.bcos.sdk.abi.datatypes.Utf8String;
import org.fisco.bcos.sdk.abi.datatypes.generated.Uint256;
import org.fisco.bcos.sdk.abi.datatypes.generated.tuples.generated.Tuple2;
import org.fisco.bcos.sdk.client.Client;
import org.fisco.bcos.sdk.contract.Contract;
import org.fisco.bcos.sdk.crypto.CryptoSuite;
import org.fisco.bcos.sdk.crypto.keypair.CryptoKeyPair;
import org.fisco.bcos.sdk.eventsub.EventCallback;
import org.fisco.bcos.sdk.model.CryptoType;
import org.fisco.bcos.sdk.model.TransactionReceipt;
import org.fisco.bcos.sdk.model.callback.TransactionCallback;
import org.fisco.bcos.sdk.transaction.model.exception.ContractException;

@SuppressWarnings("unchecked")
public class CowAssetChain extends Contract {
    public static final String[] BINARY_ARRAY = {""};

    public static final String BINARY = org.fisco.bcos.sdk.utils.StringUtils.joinAll("", BINARY_ARRAY);

    public static final String[] SM_BINARY_ARRAY = {""};

    public static final String SM_BINARY = org.fisco.bcos.sdk.utils.StringUtils.joinAll("", SM_BINARY_ARRAY);

    public static final String[] ABI_ARRAY = {"[{\"constant\":false,\"inputs\":[{\"name\":\"_earTag\",\"type\":\"string\"},{\"name\":\"_dataHash\",\"type\":\"string\"}],\"name\":\"mintCowAsset\",\"outputs\":[],\"payable\":false,\"stateMutability\":\"nonpayable\",\"type\":\"function\"},{\"constant\":true,\"inputs\":[{\"name\":\"_earTag\",\"type\":\"string\"}],\"name\":\"getCowHash\",\"outputs\":[{\"name\":\"\",\"type\":\"string\"}],\"payable\":false,\"stateMutability\":\"view\",\"type\":\"function\"},{\"anonymous\":false,\"inputs\":[{\"indexed\":false,\"name\":\"earTag\",\"type\":\"string\"},{\"indexed\":false,\"name\":\"dataHash\",\"type\":\"string\"},{\"indexed\":false,\"name\":\"timestamp\",\"type\":\"uint256\"}],\"name\":\"AssetMinted\",\"type\":\"event\"}]"};

    public static final String ABI = org.fisco.bcos.sdk.utils.StringUtils.joinAll("", ABI_ARRAY);

    public static final String FUNC_MINTCOWASSET = "mintCowAsset";

    public static final String FUNC_GETCOWHASH = "getCowHash";

    public static final Event ASSETMINTED_EVENT = new Event("AssetMinted", 
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Utf8String>() {}, new TypeReference<Uint256>() {}));
    ;

    protected CowAssetChain(String contractAddress, Client client, CryptoKeyPair credential) {
        super(getBinary(client.getCryptoSuite()), contractAddress, client, credential);
    }

    public static String getBinary(CryptoSuite cryptoSuite) {
        return (cryptoSuite.getCryptoTypeConfig() == CryptoType.ECDSA_TYPE ? BINARY : SM_BINARY);
    }

    public TransactionReceipt mintCowAsset(String _earTag, String _dataHash) {
        final Function function = new Function(
                FUNC_MINTCOWASSET, 
                Arrays.<Type>asList(new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_earTag), 
                new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_dataHash)), 
                Collections.<TypeReference<?>>emptyList());
        return executeTransaction(function);
    }

    public byte[] mintCowAsset(String _earTag, String _dataHash, TransactionCallback callback) {
        final Function function = new Function(
                FUNC_MINTCOWASSET, 
                Arrays.<Type>asList(new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_earTag), 
                new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_dataHash)), 
                Collections.<TypeReference<?>>emptyList());
        return asyncExecuteTransaction(function, callback);
    }

    public String getSignedTransactionForMintCowAsset(String _earTag, String _dataHash) {
        final Function function = new Function(
                FUNC_MINTCOWASSET, 
                Arrays.<Type>asList(new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_earTag), 
                new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_dataHash)), 
                Collections.<TypeReference<?>>emptyList());
        return createSignedTransaction(function);
    }

    public Tuple2<String, String> getMintCowAssetInput(TransactionReceipt transactionReceipt) {
        String data = transactionReceipt.getInput().substring(10);
        final Function function = new Function(FUNC_MINTCOWASSET, 
                Arrays.<Type>asList(), 
                Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Utf8String>() {}));
        List<Type> results = FunctionReturnDecoder.decode(data, function.getOutputParameters());
        return new Tuple2<String, String>(

                (String) results.get(0).getValue(), 
                (String) results.get(1).getValue()
                );
    }

    public String getCowHash(String _earTag) throws ContractException {
        final Function function = new Function(FUNC_GETCOWHASH, 
                Arrays.<Type>asList(new org.fisco.bcos.sdk.abi.datatypes.Utf8String(_earTag)), 
                Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}));
        return executeCallWithSingleValueReturn(function, String.class);
    }

    public List<AssetMintedEventResponse> getAssetMintedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(ASSETMINTED_EVENT, transactionReceipt);
        ArrayList<AssetMintedEventResponse> responses = new ArrayList<AssetMintedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            AssetMintedEventResponse typedResponse = new AssetMintedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.earTag = (String) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.dataHash = (String) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(2).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

    public void subscribeAssetMintedEvent(String fromBlock, String toBlock,
            List<String> otherTopics, EventCallback callback) {
        String topic0 = eventEncoder.encode(ASSETMINTED_EVENT);
        subscribeEvent(ABI,BINARY,topic0,fromBlock,toBlock,otherTopics,callback);
    }

    public void subscribeAssetMintedEvent(EventCallback callback) {
        String topic0 = eventEncoder.encode(ASSETMINTED_EVENT);
        subscribeEvent(ABI,BINARY,topic0,callback);
    }

    public static CowAssetChain load(String contractAddress, Client client,
            CryptoKeyPair credential) {
        return new CowAssetChain(contractAddress, client, credential);
    }

    public static CowAssetChain deploy(Client client, CryptoKeyPair credential) throws
            ContractException {
        return deploy(CowAssetChain.class, client, credential, getBinary(client.getCryptoSuite()), "");
    }

    public static class AssetMintedEventResponse {
        public TransactionReceipt.Logs log;

        public String earTag;

        public String dataHash;

        public BigInteger timestamp;
    }
}
